// ===== module imports (6.0.0; generated by build/convert-esm-pass2.mjs) =====
import { safeLog } from './03-memory-management.js';
import { escapeHtml, toLocalDateString } from './00-header.js';
import { doc, onSnapshot } from './01-firebase-imports.js';
import { scheduleSelector } from './02-dom-elements.js';
import { setActiveSchedule } from './16-schedule-management.js';
import { recalculateAndRenderAll } from './18-bell-crud-and-modals.js';
import { state } from './state.js';

// ============================================================
// V5.73.0 (PARKED in V5.74.0) — REVIVED V6.10.0 (design Layer 4, Verb A)
//
// The park note below demanded a per-teacher assignment model before this
// could ship. Layers 2–3 built exactly that, so the gate comes off:
//   - v2 schema: config/schedule_calendar.days[date].entries =
//     [{ scope:[uids], verb:'base', scheduleId }] — scopes are EXPLICIT uid
//     lists built by the Layer 3 filter-picker (34-day-designation.js);
//     tags filter the picker, never resolve at runtime.
//   - each client resolves ITS OWN designation:
//     resolveCalendarSchedule(cal, today, state.userId) (engine 1.7.0;
//     v1 exceptions/weekdayDefaults still work as the unscoped fallback).
//   - manual choice today still wins (MANUAL_SCHEDULE_CHOICE_KEY, stamped
//     by the selector listener in the init chunk) — but deviation is now
//     BANNERED (I1): amber, "designated to X", Follow button clears the
//     manual choice and switches; dismiss hides for the session.
//   - I4: when designated to an alternate base, personal reminder bells
//     whose recorded home base (relative.baseScheduleId, 6.8.0) is a
//     DIFFERENT schedule are counted into the banner text — they may not
//     apply today (the Orphaned Bells period shows the specifics).
// The old `enabled` flag is retired; presence of a v2 `days` map (or the
// old v1 fields) IS the enablement. Every guard still fails closed.
// ============================================================

let scheduleCalendar = null;                    // live copy of the config doc
let scheduleCalendarListenerUnsubscribe = null;
let calendarPendingExceptions = {};             // modal working copy

const MANUAL_SCHEDULE_CHOICE_KEY = 'manualScheduleChoiceDate';

function listenForScheduleCalendar() {
    if (scheduleCalendarListenerUnsubscribe) {
        scheduleCalendarListenerUnsubscribe();
        scheduleCalendarListenerUnsubscribe = null;
    }
    if (!state.db) return;
    const calRef = doc(state.db, 'artifacts', state.appId, 'public', 'data', 'config', 'schedule_calendar');
    scheduleCalendarListenerUnsubscribe = onSnapshot(calRef, (docSnap) => {
        scheduleCalendar = docSnap.exists() ? docSnap.data() : null;
        applyCalendarSchedule('calendar-updated');
    }, (error) => {
        console.error('Error listening to schedule calendar:', error);
    });
}

/**
 * Switch to the calendar-designated schedule if the rules above allow it.
 * Safe to call any time; every guard fails closed (no switch).
 */
function applyCalendarSchedule(trigger) {
    try {
        // V6.12.0 (Verb B): transformation recipes are INDEPENDENT of base
        // designation — refresh them first, on every trigger, before any
        // base-switch path returns. (No calendar => [], self-clears.)
        refreshActiveTransforms();

        if (!state.allSchedules || state.allSchedules.length === 0) return;
        const today = new Date();

        // V6.14.0: resolution order is
        //   (1) SCOPED calendar designation  — mandate, building wins, bannered
        //   (2) school-wide exception/weekday — mandate (rare at Ellis), bannered
        //   (3) HOME schedule (per-teacher)   — silent default, never bannered
        // Steps 1+2 together reproduce the old resolveCalendarSchedule(uid)
        // result and behavior exactly; step 3 is the new per-teacher layer,
        // which is why home must be reachable even with NO calendar doc.
        const scopedId = scheduleCalendar
            ? window.BellEngine.resolveScopedDesignation(scheduleCalendar, today, state.userId || undefined)
            : null;
        if (scopedId) { applyMandate(scopedId, today, trigger); return; }

        const schoolWideId = scheduleCalendar
            ? window.BellEngine.resolveCalendarSchedule(scheduleCalendar, today) // no uid -> exception/weekday only
            : null;
        if (schoolWideId) { applyMandate(schoolWideId, today, trigger); return; }

        applyHomeSchedule(today, trigger);
    } catch (e) {
        console.error('applyCalendarSchedule failed:', e);
    }
}

// A calendar MANDATE (scoped designation or school-wide default): the
// building's decision. Auto-follow unless a same-day manual choice deviates,
// in which case banner it (I1). Behavior identical to the pre-6.14.0 path.
function applyMandate(designatedId, today, trigger) {
    if (!state.allSchedules.some(s => s.id === designatedId)) {
        console.warn(`Calendar designates schedule "${designatedId}" which no longer exists — ignoring.`);
        return;
    }
    const targetPrefixed = `shared-${designatedId}`;
    const currentPrefixed = scheduleSelector ? scheduleSelector.value : '';
    if (localStorage.getItem(MANUAL_SCHEDULE_CHOICE_KEY) === toLocalDateString(today)) {
        syncDesignationBanner(currentPrefixed !== targetPrefixed
            ? { designatedId, targetPrefixed } : null);
        return;
    }
    if (currentPrefixed.startsWith('personal-')) { syncDesignationBanner(null); return; }
    if (currentPrefixed === targetPrefixed) { syncDesignationBanner(null); return; }
    safeLog.log(`[Calendar] Auto-switching to "${designatedId}" (trigger: ${trigger}).`);
    if (scheduleSelector) scheduleSelector.value = targetPrefixed;
    setActiveSchedule(targetPrefixed);
    syncDesignationBanner(null);
    noteForeignAnchors(designatedId);
}

// V6.14.0: the HOME schedule (per-teacher standing default) — a convenience,
// NOT a building mandate, so it is applied SILENTLY (no banner). It never
// yanks a personal-schedule user (that's a deliberate choice with an overlay)
// and never overrides a same-day manual pick. Absent all of those, it brings
// a teacher back to their normal schedule at day change / sign-in.
function applyHomeSchedule(today, trigger) {
    syncDesignationBanner(null); // no mandate; banner reflects transforms only
    const homeId = state.homeScheduleId;
    if (!homeId) return;
    if (!state.allSchedules.some(s => s.id === homeId)) return; // home schedule was deleted
    const targetPrefixed = `shared-${homeId}`;
    const currentPrefixed = scheduleSelector ? scheduleSelector.value : '';
    if (localStorage.getItem(MANUAL_SCHEDULE_CHOICE_KEY) === toLocalDateString(today)) return;
    if (currentPrefixed.startsWith('personal-')) return;
    if (currentPrefixed === targetPrefixed) return;
    safeLog.log(`[Home] Auto-loading home schedule "${homeId}" (trigger: ${trigger}).`);
    if (scheduleSelector) scheduleSelector.value = targetPrefixed;
    setActiveSchedule(targetPrefixed);
}

// V6.14.0: watch this user's own roster doc for their home (default) schedule.
// roster/{uid} is self-readable (rules). Live: if an admin sets/changes it,
// the client re-resolves (and may silently switch) at once.
let homeListenerUnsub = null;
function listenForHomeSchedule() {
    if (homeListenerUnsub) { homeListenerUnsub(); homeListenerUnsub = null; }
    if (!state.db || !state.userId) return;
    const ref = doc(state.db, 'artifacts', state.appId, 'public', 'data', 'roster', state.userId);
    homeListenerUnsub = onSnapshot(ref, (snap) => {
        const data = snap.exists() ? snap.data() : null;
        const next = (data && typeof data.defaultScheduleId === 'string' && data.defaultScheduleId)
            ? data.defaultScheduleId : null;
        if (next !== state.homeScheduleId) {
            state.homeScheduleId = next;
            applyCalendarSchedule('home-updated');
        }
    }, (err) => { console.warn('Home-schedule listen error:', err && err.message); });
}

// ===== V6.12.0: Verb B — resolve today's transformation recipes =====
// Mirrors how module 16 stamps state.activeSharedScheduleShift: this stores
// the resolved recipe list on state for module 14's resolveAllBellTimes to
// apply to base-period copies. Also builds a human summary for the I1 banner.
let activeTransformSummary = ''; // '' when no transform applies today

function refreshActiveTransforms() {
    const recipes = window.BellEngine.resolveCalendarTransforms(
        scheduleCalendar, new Date(), state.userId || undefined) || [];
    activeTransformSummary = describeTransforms(recipes);
    const prev = JSON.stringify(state.activeCalendarTransforms || []);
    const next = JSON.stringify(recipes);
    if (prev !== next) {
        state.activeCalendarTransforms = recipes;
        safeLog.log('[Calendar] Verb B: ' + recipes.length + ' transform recipe(s) active today.');
        recalculateAndRenderAll(); // re-derive bell times with the new recipe set
    }
}

function fmtTime(t) {
    return (typeof t === 'string' && t)
        ? window.BellEngine.formatTime12Hour(t, true) : '';
}

function describeRecipe(r) {
    if (!r || typeof r !== 'object') return '';
    if (r.type === 'shift') {
        const secs = Math.trunc(Number(r.offsetSeconds)) || 0;
        if (!secs) return '';
        const mins = Math.round(Math.abs(secs) / 60);
        let s = 'bells ' + mins + ' min ' + (secs > 0 ? 'later' : 'earlier');
        if (r.from && r.until) s += ' between ' + fmtTime(r.from) + ' and ' + fmtTime(r.until);
        else if (r.from) s += ' from ' + fmtTime(r.from) + ' on';
        else if (r.until) s += ' up to ' + fmtTime(r.until);
        return s;
    }
    if (r.type === 'shorten') {
        const per = Math.round((Math.trunc(Number(r.perPeriodSeconds)) || 0) / 60);
        if (per <= 0 || !r.after) return '';
        let s = 'periods after ' + fmtTime(r.after) + ' shortened ' + per + ' min';
        if (r.extendPeriodName) s += ' to extend ' + r.extendPeriodName;
        return s;
    }
    return '';
}

function describeTransforms(recipes) {
    if (!Array.isArray(recipes) || !recipes.length) return '';
    return recipes.map(describeRecipe).filter(Boolean).join('; ');
}

// ===== V6.10.0: designation banner (I1) + foreign-anchor note (I4) =====
let designationBannerDismissed = false;

function foreignAnchorCount(designatedId) {
    let n = 0;
    for (const p of (state.personalBellsPeriods || [])) {
        for (const b of (p.bells || [])) {
            if (b && b.relative && b.relative.baseScheduleId
                    && b.relative.baseScheduleId !== designatedId) n++;
        }
    }
    return n;
}

function noteForeignAnchors(designatedId) {
    const n = foreignAnchorCount(designatedId);
    if (n) safeLog.log('[Calendar] I4: ' + n + ' personal reminder bell(s) were anchored to a different base and may not apply today.');
}

/**
 * V6.12.0: single driver for the I1 banner. Composes two independent facts:
 *   - base deviation (arg `deviation` = { designatedId, targetPrefixed } when
 *     the user is NOT on their designated base; null otherwise) — carries the
 *     Follow button and the I4 foreign-anchor count;
 *   - active transforms (module-level activeTransformSummary) — surfaced so a
 *     teacher understands WHY today's bells moved even with no base deviation.
 * The Follow button only makes sense for base deviation, so it is hidden in
 * transform-only mode. If neither fact is present, the banner hides.
 */
function syncDesignationBanner(deviation) {
    const banner = document.getElementById('designation-banner');
    const text = document.getElementById('designation-text');
    const followBtn = document.getElementById('designation-follow');
    if (!banner || !text) return;
    if (designationBannerDismissed) { banner.classList.add('hidden'); return; }

    let html = '';
    if (deviation && deviation.designatedId) {
        const sched = state.allSchedules.find(s => s.id === deviation.designatedId);
        const n = foreignAnchorCount(deviation.designatedId);
        html = 'Today you are designated to <span class="font-medium">'
            + escapeHtml(sched ? sched.name : deviation.designatedId) + '</span>.'
            + (n ? ' <span class="text-xs">(' + n + ' of your reminder bells may not apply there.)</span>' : '');
        if (followBtn) { followBtn.dataset.target = deviation.targetPrefixed; followBtn.classList.remove('hidden'); }
    } else if (followBtn) {
        followBtn.classList.add('hidden');
    }
    if (activeTransformSummary) {
        html += html
            ? ' <span class="text-xs">Also today: ' + escapeHtml(activeTransformSummary) + '.</span>'
            : "Today's bells are adjusted: " + escapeHtml(activeTransformSummary) + '.';
    }
    if (!html) { banner.classList.add('hidden'); return; }
    text.innerHTML = html;
    banner.classList.remove('hidden');
}

function hideDesignationBanner() {
    const banner = document.getElementById('designation-banner');
    if (banner) banner.classList.add('hidden');
}

(function wireDesignationBanner() {
    const followBtn = document.getElementById('designation-follow');
    const dismissBtn = document.getElementById('designation-dismiss');
    if (followBtn) followBtn.addEventListener('click', () => {
        localStorage.removeItem(MANUAL_SCHEDULE_CHOICE_KEY); // un-deviate
        const target = followBtn.dataset.target;
        if (target && scheduleSelector) scheduleSelector.value = target;
        if (target) setActiveSchedule(target);
        hideDesignationBanner();
    });
    if (dismissBtn) dismissBtn.addEventListener('click', () => {
        designationBannerDismissed = true;
        hideDesignationBanner();
    });
})();

// ===== module exports (6.0.0; +6.10.0 revival; +6.12.0 describeRecipe) =====
export {
    MANUAL_SCHEDULE_CHOICE_KEY,
    applyCalendarSchedule,
    listenForScheduleCalendar,
    listenForHomeSchedule, // v6.14.0: per-teacher home schedule listener
    describeRecipe, // v6.12.0: shared label text so module 34's entry list
                    //   and this banner never drift
};
